VALUES
  ('optometrist-moex-00354', 'optometrist', 'optometrist-moex-113-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '依據醫療法下列敘述何者正確？①醫療法所稱醫療法人，包括醫療財團法人及醫療社團法人  ②醫療', '["醫療機構之負責醫師，以在中央主管機關指定之醫院、診 所接受三年以上之醫師訓練並取得證明文件者為限", "醫療社團法人，非依醫療法規定不得設立  ⑤ 醫療機構收取醫療費用之標準，由直轄市、縣（市）主管機關核定之", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "87d2d58d5233", "answer_pdf_sha1": "d9cba2739812", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 49, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00355', 'optometrist', 'optometrist-moex-113-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '驗光人員為民眾驗光時，應符合下列何種醫學倫理原則？①符合公平正義原則  ②被驗光者有「知', '["進行驗光前應獲得被驗光者的同意", "關注被驗光者的最佳利益 並善盡保密的責任", "僅", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "87d2d58d5233", "answer_pdf_sha1": "d9cba2739812", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 50, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00356', 'optometrist', 'optometrist-moex-113-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '關於不等視（anisometropia）、不等像（aniseikonia）的檢查敘述，下列何者最不適當？', '["Brücknertest可以用來篩檢嬰兒與幼兒的不等視", "Brücknertest是利用間接式眼底鏡（indirectophthalmoscope）操作", "透過配戴偏光鏡（polaroidglasses）看美國光學矢量圖卡（AmericanOpticalvectographiccardsforadults） 可檢測出不等像（aniseikonia）", "透過Brücknertest發現兩眼紅反射（redreflex）的亮度不同，表示可能有斜視或不等視"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "56b79c9a9e45", "answer_pdf_sha1": "8080996efa52", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00357', 'optometrist', 'optometrist-moex-113-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有關動眼功能異常（OcularMotorDysfunction）如平順追視（pursuit）、跳躍追視（saccadic）及固視（fixation）', '["屈光異常的矯正", "運用附加鏡片調整", "視覺訓練", "開刀處理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "56b79c9a9e45", "answer_pdf_sha1": "8080996efa52", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0903", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
